#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int N, M; cin >> N >> M;
    vector<vector<int>> adj(N + 1);
    for (int i = 0; i < M; i++) {
        int a, b; cin >> a >> b;
        adj[a].push_back(b);
        adj[b].push_back(a);
    }
    vector<int> dist(N + 1, -1);
    queue<int> q;
    q.push(1); dist[1] = 0;
    while (!q.empty()) {
        int cur = q.front(); q.pop();
        for (int nx : adj[cur]) {
            if (dist[nx] == -1) { dist[nx] = dist[cur] + 1; q.push(nx); }
        }
    }
    for (int i = 1; i <= N; i++) {
        cout << dist[i];
        if (i < N) cout << ' ';
    }
    cout << "\n";
    return 0;
}
